<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --directory-url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://gateway.example.org/soradns/directory/latest.car</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
